const all = $input.all();
const perf = all[0]?.json || {};
const assets = all[1]?.json || {};
const campaign = $node['split'].json;

const cost = parseFloat(perf.cost || 0);
const conversions = parseInt(perf.conversions || 0);
const convValue = parseFloat(perf.conversion_value || 0);
const ctr = parseFloat(perf.ctr || 0);
const impressionShare = parseFloat(perf.impression_share || 0);
const avgCpc = parseFloat(perf.avg_cpc || 0);

const roas = cost > 0 ? convValue / cost : 0;
const cpa = conversions > 0 ? cost / conversions : null;
const bidMaturity = campaign.bid_strategy_type === 'MAXIMIZE_CONVERSION_VALUE' ? 'advanced' : (campaign.bid_strategy_type === 'TARGET_ROAS' ? 'target' : 'basic');

const assetHealthScore = assets.asset_group || {};
const textAssetQuality = assetHealthScore.text_assets?.filter(a => a.pinned === false).length || 0;
const imageAssetQuality = assetHealthScore.image_assets?.filter(a => a.enabled === true).length || 0;
const videoAssetQuality = assetHealthScore.video_assets?.filter(a => a.enabled === true).length || 0;

const lowImpShare = impressionShare < 0.7;
const lowCtr = ctr < 1.0;
const budgetConstrained = impressionShare > 0.8 && (perf.budget_limit_reached === true);
const poorAssetMix = textAssetQuality < 3 || imageAssetQuality < 2;

const issues = [];
if (lowImpShare) issues.push({issue: 'low_impression_share', severity: 'medium', value: (impressionShare * 100).toFixed(1) + '%'});
if (lowCtr) issues.push({issue: 'low_ctr', severity: 'low', value: ctr.toFixed(2) + '%'});
if (budgetConstrained) issues.push({issue: 'budget_constrained', severity: 'high', value: 'yes'});
if (poorAssetMix) issues.push({issue: 'insufficient_assets', severity: 'high', value: `text=${textAssetQuality}, img=${imageAssetQuality}, vid=${videoAssetQuality}`});

return [{ json: {
  campaign_id: campaign.id,
  campaign_name: campaign.name,
  client_id: campaign.client_id,
  date: new Date().toISOString().slice(0, 10),
  cost: Math.round(cost * 100) / 100,
  conversions,
  conversion_value: Math.round(convValue * 100) / 100,
  roas: Math.round(roas * 100) / 100,
  cpa: cpa ? Math.round(cpa * 100) / 100 : null,
  ctr: Math.round(ctr * 1000) / 10,
  impression_share: (impressionShare * 100).toFixed(1),
  avg_cpc: Math.round(avgCpc * 100) / 100,
  bid_maturity: bidMaturity,
  asset_health: {
    text_assets: textAssetQuality,
    image_assets: imageAssetQuality,
    video_assets: videoAssetQuality
  },
  health_issues: issues,
  is_healthy: issues.length === 0
} }];

